const express = require('express');
const router = express.Router();
const tasksService = require('../tasks/service');
const { sendError } = require('../../lib/errors');

router.get('/', async (req, res) => {
  const projectId = req.params.projectId;
  const status = req.query.status;
  try {
    const tasks = await tasksService.getTasks(projectId, status);
    res.json({ tasks });
  } catch (error) {
    sendError(res, error.statusCode || 500, error.code, error.message);
  }
});

router.post('/', async (req, res) => {
  const projectId = req.params.projectId;
  const { title } = req.body;
  if (!title) {
    return sendError(res, 400, 'BAD_REQUEST', 'Title is required');
  }
  try {
    const task = await tasksService.createTask(projectId, title);
    res.status(201).json({ task });
  } catch (error) {
    sendError(res, error.statusCode || 500, error.code, error.message);
  }
});

router.patch('/:taskId', async (req, res) => {
  const projectId = req.params.projectId;
  const taskId = req.params.taskId;
  const { status } = req.body;
  if (!['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'BAD_REQUEST', 'Invalid status');
  }
  try {
    const task = await tasksService.updateTaskStatus(projectId, taskId, status);
    res.json({ task });
  } catch (error) {
    sendError(res, error.statusCode || 500, error.code, error.message);
  }
});

module.exports = router;
