      "content": "// src/modules/tasks/service.js
const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');

let tasksStore = {};

async function getTasks(projectId, status) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) {
    throw { statusCode: 404, code: 'NOT_FOUND', message: 'Project not found' };
  }
  let tasks = tasksStore[projectId] || [];
  if (status === 'done') {
    tasks = tasks.filter(task => task.status === 'done');
  }
  return tasks;
}

async function createTask(projectId, title) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) {
    throw { statusCode: 404, code: 'NOT_FOUND', message: 'Project not found' };
  }
  const task = {
    id: randomUUID(),
    title,
    status: 'todo'
  };
  tasksStore[projectId] = (tasksStore[projectId] || []).concat(task);
  return task;
}

async function updateTaskStatus(projectId, taskId, status) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) {
    throw { statusCode: 404, code: 'NOT_FOUND', message: 'Project not found' };
  }
  let tasks = tasksStore[projectId] || [];
  const taskIndex = tasks.findIndex(task => task.id === taskId);
  if (taskIndex === -1) {
    throw { statusCode: 404, code: 'NOT_FOUND', message: 'Task not found' };
  }
  tasks[taskIndex].status = status;
  return tasks[taskIndex];
}

module.exports = {
  getTasks,
  createTask,
  updateTaskStatus
};
